// Gera 1 item por CNPJ com TODAS as colunas pedidas (nomes iguais aos do SAP/planilha)
function S(v) { return (v === undefined || v === null) ? '' : String(v).trim(); }
return $input.all().map((item, idx) => {
  const j = item.json;
  const out = { ...j };

  const cardTypeIn = S(j.CardType || '');
  out.CardCode = S(j.codigo_pn || j.CardCode);
  out.CardName = S(j.razao_social || j.CardName);
  out.CardType = cardTypeIn === 'S' ? 'cSupplier' : (cardTypeIn === 'L' ? 'cLead' : 'cCustomer');
  out.AliasName = S(j.nome_fantasia || j.AliasName);
  out.Phone1 = S(j.ddd_telefone_1 || j.Phone1);
  out.Phone2 = S(j.ddd_telefone_2 || j.Phone2);
  out.U_TX_IndIEDest = S(j.U_TX_IndIEDest || '9');
  out.U_TX_IndFinal = S(j.U_TX_IndFinal || '0');
  out.U_TX_SN = S(j.U_TX_SN || '0');

  out._idx = idx;
  return { json: out };
});

// OCRD - Retorna APENAS o JSON com os campos mínimos exigidos p/ criação no SAP
const S = (v) => (v === undefined || v === null) ? '' : String(v).trim();
return $input.all().map(item => {
  const j = item.json;
  const cardTypeIn = S(j.CardType || '');

  return {
    json: {
      CardCode: S(j.codigo_pn || j.CardCode),
      CardName: S(j.razao_social || j.CardName),
      CardType: cardTypeIn === 'S' ? 'cSupplier' : (cardTypeIn === 'L' ? 'cLead' : 'cCustomer'),
      U_TX_SN: S(j.U_TX_SN || '0')
    }
  };
});

// n8n Code (JavaScript) — runOnceForAllItems
const S = (v) => (v === undefined || v === null) ? '' : String(v).trim();
const toYN = (v) => (v === true || String(v).toUpperCase() === 'Y' || String(v).toUpperCase() === 'T') ? 'tYES' : 'tNO';
return $input.all().map(item => {
  const j = item.json;
  const cardTypeIn = S(j.CardType || '');
  const payload = {
    CardCode: S(j.codigo_pn || j.CardCode),
    CardName: S(j.razao_social || j.CardName),
    CardType: cardTypeIn === 'S' ? 'cSupplier' : (cardTypeIn === 'L' ? 'cLead' : 'cCustomer'),
    AliasName: S(j.nome_fantasia || j.AliasName),
    Phone1: S(j.Phone1),
    Phone2: S(j.Phone2),
    EmailAddress: S(j.EmailAddress || j.email),
    Valid: toYN(j.Valid),
    Frozen: toYN(j.Frozen),
    U_TX_IndIEDest: S(j.U_TX_IndIEDest || '9'),
    U_TX_IndFinal: S(j.U_TX_IndFinal || '0'),
    U_TX_SN: S(j.U_TX_SN || '0')
  };
  return {
    json: {
      ...j,
      payload: payload
    }
  };
});

