const map = new Map();
for (const { json: j } of items) {
  const key = String(j.CardCode);
  if (!map.has(key)) map.set(key, { CardCode: key, BPAddresses: [] });
  map.get(key).BPAddresses.push({
    AddressName: j.Address,          // "Cobranca" | "Entrega"
    AddressType: j.AdresType,        // "bo_BillTo" | "bo_ShipTo"
    Street: j.Street || "",
    StreetNo: String(j.StreetNo ?? ""),
    Building: j.Building || "",
    Block: j.Block || "",
    ZipCode: j.ZipCode || "",
    City: j.City || "",
    County: String(j.County ?? ""),
    State: j.State || "",
    Country: j.Country || "BR",
  });
}
return Array.from(map.values()).map(x => ({ json: x }));

// headers completos do LOGIN (precisa de "Include Response Headers and Status" ON no Login)
const H = $json.headers || {};
// pode vir string ou array; normalizamos para uma string única
const rawSetCookie = []
  .concat(H['set-cookie'] || H['Set-Cookie'] || [])
  .flat()
  .join('; ');

// extrai exatamente o que o SL mandou
const b1sessionFromCookie = (rawSetCookie.match(/B1SESSION=([^;]+)/i) || [])[1] || '';
const routeIdFromCookie   = (rawSetCookie.match(/ROUTEID=([^;]+)/i)  || [])[1] || '';

// fallback: body também traz SessionId em alguns ambientes
const body = $json.body ?? $json;
const sessionFromBody = body?.SessionId || $json?.SessionId || '';

const sessionId = b1sessionFromCookie || sessionFromBody;
if (!sessionId) throw new Error('SessionId/B1SESSION não encontrado no Login');

const cookie = routeIdFromCookie
  ? `B1SESSION=${sessionId}; ROUTEID=${routeIdFromCookie}`
  : `B1SESSION=${sessionId}`;

return [{ json: { sessionId, routeId: routeIdFromCookie, cookie, rawSetCookie } }];

const { sessionId, routeId } = $json;
if (!sessionId) throw new Error('Sem sessionId');

const cookie = routeId
  ? `B1SESSION=${sessionId}; ROUTEID=${routeId}`
  : `B1SESSION=${sessionId}`; // fallback se não vier routeId

return [{ json: { cookie } }];

return items.map(item => {
  const j = item.json || {};
  const p = j.payload ? { ...j.payload } : {};

  const addrs = Array.isArray(j.BPAddresses) ? j.BPAddresses : [];

  p.BPAddresses = addrs.map(a => ({
    AddressName: String(a.AddressName || a.Address || ''),
    AddressType: String(a.AddressType || a.AdresType || ''), // bo_BillTo | bo_ShipTo
    Street:      String(a.Street || ''),
    StreetNo:    String(a.StreetNo ?? ''),
    // 🔁 CORREÇÃO: usar BuildingFloorRoom (e não Building)
    BuildingFloorRoom: String(a.Building || a.BuildingFloorRoom || ''),
    Block:       String(a.Block || ''),
    ZipCode:     String(a.ZipCode || ''),
    City:        String(a.City || ''),
    County:      String(a.County ?? ''),  // ok como string
    State:       String(a.State || ''),
    Country:     String(a.Country || 'BR'),
  }));

  return { json: { ...j, payload: p } };
});

