// Agrupa linhas CRD7 por ParentKey e remove duplicidade ParentKey+LineNum (E09)

const map = new Map();

for (const { json: j } of items) {
  const key = String(j.ParentKey ?? j.CardCode ?? '').trim();
  if (!key) continue; // (deixe para a validação formal marcar E01 se preferir)

  if (!map.has(key)) {
    map.set(key, { ParentKey: key, CRD7: [] });
  }

  const lineNumStr = String(j.LineNum ?? '');
  const bucket = map.get(key).CRD7;

  // evita duplicidade ParentKey+LineNum (E09)
  const exists = bucket.find(x => String(x.LineNum) === lineNumStr);
  if (!exists) {
    bucket.push({
      LineNum: lineNumStr,                      // manter string aqui; convert. p/ Number no PATCH se quiser
      Address: String(j.Address ?? ''),
      CNAECode: String(j.CNAEAbsId ?? ''),
      TaxId0: String(j.TaxId0 ?? ''),
      TaxId1: String(j.TaxId1 ?? ''),
      TaxId3: String(j.TaxId3 ?? ''),
      TaxId4: String(j.TaxId4 ?? ''),
      TaxId7: String(j.TaxId7 ?? ''),
      TaxId8: String(j.TaxId8 ?? ''),
    });
  }
}

// Saída: [{ json: { ParentKey, CRD7: [...] } }, ...]
return Array.from(map.values()).map(x => ({ json: x }));

// Prepara chave de merge e saneia a coleção CRD7 no mesmo passo
function onlyDigits(s){ return String(s ?? '').replace(/\D/g,''); }
function normalizeAddress(a){
  const v = String(a ?? '');
  if (v.toLowerCase() === 'cobrança') return 'Cobranca';
  return v;
}
return $input.all().map(({ json }) => {
  const key = String(json.ParentKey ?? json.CardCode ?? '').trim();
  const rows = Array.isArray(json.CRD7) ? json.CRD7.map(r => {
    return {
      LineNum : String(r.LineNum ?? ''),
      Address : normalizeAddress(r.Address),
      CNAECode: onlyDigits(r.CNAECode),
      TaxId0  : String(r.TaxId0),
      TaxId1  : String(r.TaxId1 ?? '').trim(),
      TaxId3  : String(r.TaxId3 ?? '').trim(),
      TaxId4  : onlyDigits(r.TaxId4),
      TaxId7  : String(r.TaxId7 ?? '').trim(),
      TaxId8  : String(r.TaxId8 ?? '').trim(),
    };
  }) : [];
  return {
    json: {
      ...json,
      ParentKey: key,
      CardCode : key,
      CRD7     : rows
    }
  };
});

const COLLECTION = 'BPFiscalTaxIDCollection';

return items.map(item => {
  const j = item.json || {};
  const p = j.payload ? { ...j.payload } : {};
  const rows = Array.isArray(j.CRD7) ? j.CRD7 : [];

  p[COLLECTION] = rows.map(r => ({
    LineNum: Number(r.LineNum ?? 0),
    Address: String(r.Address ?? ''),
    CNAECode: Number(r.CNAECode),        // << envia o ID interno
    TaxId0: String(r.TaxId0 ?? ''),
    TaxId1: String(r.TaxId1 ?? ''),
    TaxId3: String(r.TaxId3 ?? ''),
    TaxId4: String(r.TaxId4 ?? ''),
    TaxId7: String(r.TaxId7 ?? ''),
    TaxId8: String(r.TaxId8 ?? ''),
  }));

  return { json: { ...j, payload: p } };
});

// Prepara o corpo do PATCH a partir do payload já montado
return items.map(item => {
  const j = item.json || {};
  const p = j.payload ? { ...j.payload } : {};

  // (opcional) saneio final leve
  // - garante que as coleções existam como arrays
  p.BPAddresses = Array.isArray(p.BPAddresses) ? p.BPAddresses : [];
  p.BPFiscalTaxIDCollection = Array.isArray(p.BPFiscalTaxIDCollection) ? p.BPFiscalTaxIDCollection : [];

  // Devolve num campo separado para apontar no HTTP
  return { json: { ...j, bodyPatch: p } };
});

/**
 * n8n - Code Node (runOnceForEachItem)
 */
const j = $json;
try {
  const deepClone = (obj) => (obj ? JSON.parse(JSON.stringify(obj)) : obj);
  const toYesNo = (v) => {
    if (typeof v === 'string') {
      const s = v.trim().toLowerCase();
      if (s === 'tyes' || s === 'yes' || s === 'true') return 'tYES';
      if (s === 'tno'  || s === 'no'  || s === 'false') return 'tNO';
      return v;
    }
    if (typeof v === 'boolean') return v ? 'tYES' : 'tNO';
    return v ?? undefined;
  };
  const stripLineNum = (arr) => {
    if (!Array.isArray(arr)) return arr;
    return arr.map((row) => {
      if (!row || typeof row !== 'object') return row;
      const { LineNum, ...rest } = row;
      return rest;
    });
  };
  const ensureNumberOrString = (v) => {
    if (v === null || v === undefined) return v;
    const n = Number(v);
    return Number.isFinite(n) ? n : v;
  };
  const normalizeFiscalFromCRD7 = (crd7) => {
    if (!Array.isArray(crd7)) return undefined;
    return crd7.map((r) => ({
      Address: r.Address ?? '',
      CNAECode: ensureNumberOrString(r.CNAECode),
      TaxId0: r.TaxId0 ?? '',
      TaxId1: r.TaxId1 ?? '',
      TaxId3: r.TaxId3 ?? '',
      TaxId4: r.TaxId4 ?? '',
      TaxId7: r.TaxId7 ?? '',
      TaxId8: r.TaxId8 ?? '',
    }));
  };
  const normalizeAddresses = (arr) => {
    if (!Array.isArray(arr)) return undefined;
    return arr.map((a) => ({
      AddressName: a.AddressName ?? '',
      AddressType: a.AddressType ?? '',
      Street: a.Street ?? '',
      StreetNo: a.StreetNo ?? '',
      BuildingFloorRoom: a.BuildingFloorRoom !== undefined ? a.BuildingFloorRoom : (a.Building !== undefined ? a.Building : ''),
      Block: a.Block ?? '',
      ZipCode: a.ZipCode ?? '',
      City: a.City ?? '',
      County: a.County ?? '',
      State: a.State ?? '',
      Country: a.Country ?? '',
    }));
  };

  let src;
  if (j.bodyPatch && typeof j.bodyPatch === 'object') {
    src = deepClone(j.bodyPatch);
  } else if (j.payload && typeof j.payload === 'object') {
    src = deepClone(j.payload);
  } else {
    src = {
      CardCode: j.CardCode,
      CardName: j.CardName,
      CardType: j.CardType,
      AliasName: j.AliasName,
      Phone1: j.Phone1,
      Phone2: j.Phone2,
      Valid: j.Valid ?? toYesNo(j.validFor),
      Frozen: j.Frozen ?? toYesNo(j.frozenFor),
      U_TX_IndIEDest: j.U_TX_IndIEDest,
      U_TX_IndFinal: j.U_TX_IndFinal,
      U_TX_SN: j.U_TX_SN,
    };
    const fiscalFromTop = normalizeFiscalFromCRD7(j.CRD7);
    if (fiscalFromTop) src.BPFiscalTaxIDCollection = fiscalFromTop;
    const addrFromTop = normalizeAddresses(j.BPAddresses);
    if (addrFromTop) src.BPAddresses = addrFromTop;
  }

  if (src.Valid === undefined && j.validFor !== undefined) src.Valid = toYesNo(j.validFor);
  if (src.Frozen === undefined && j.frozenFor !== undefined) src.Frozen = toYesNo(j.frozenFor);

  src.BPFiscalTaxIDCollection = stripLineNum(src.BPFiscalTaxIDCollection || normalizeFiscalFromCRD7(j.CRD7));
  src.BPAddresses = normalizeAddresses(src.BPAddresses || j.BPAddresses);

  for (const k of Object.keys(j)) {
    if (k.startsWith('U_')) {
      const v = j[k];
      if (v !== undefined && v !== null && v !== '' && src[k] === undefined) {
        src[k] = v;
      }
    }
  }
  delete src['@odata.context'];
  delete src.value;
  return src;
} catch (e) {
  return {
    error: true,
    message: e?.message || 'Falha ao preparar body (POST)',
    debugInput: j ?? null,
  };
}

// Run Once for All Items
const rows = $input.all();
return rows.map(({ json }) => {
  // CNAECode sempre do CRD7 (já veio no item)
  const digits = v => String(v ?? '').replace(/\D/g,'');
  const code = digits(json.CNAECode).padStart(7,'0');
  json.CNAECode = code;

  // AbsId enriquecido via Merge (OCNA) — nomes típicos:
  const id = Number(digits(json.CNAEAbsId ?? json.OCNAAbsId ?? json.CNAEId));
  if (Number.isFinite(id)) {
    json.CNAEAbsId = id;
    json.CNAEId    = id;
    delete json._cnaeError;
  } else {
    json._cnaeError = `CNAE sem de-para: ${code || '(vazio)'}`;
  }
  return { json };
});

return items.map(({ json }) => {
  json.CNAEId = (json.CNAEId ?? '').toString().trim();
  // garanta o nome do id: CNAEAbsid  (algumas saídas aparecem como CNAEAbsId/CNAEId)
  if (json.CNAEId&& !json.CNAEAbsid) json.CNAEAbsid = json.CNAEId;
  if (json.CNAEAbsId && !json.CNAEAbsid) json.CNAEAbsid = json.CNAEAbsId;
  return { json };
});

// n8n Code Node (runOnceForEachItem)
function cleanStr(v){ if(v==null) return ""; return String(v).trim(); }
function onlyDigits(v){ return cleanStr(v).replace(/\D/g,''); }

const item = $json;

return {
  ...item,
  "__row": (item.__row != null) ? item.__row : 2,
  "codigo_pn": onlyDigits(item.cnpj || item.CNPJ || ""),
  "nome_pn": cleanStr(item.razao_social || item.Nome || ""),
  "phone1": onlyDigits(item.telefone || ""),
  "email": cleanStr(item.email || ""),
  "currency": "##",
  "groupCode": 100
};

return items.map((item, idx) => {
  const raw = (item.json.CNPJ ?? '').toString();
  const num = raw.replace(/\D/g, '');
  return { json: { ...item.json, cnpj_raw: raw, cnpj_num: num, __row: idx + 2 } };
});
